def test_simple():
    rl = rewriterule(Basic(p, S(1)), Basic(p, S(2)), variables=(p,))
    assert list(rl(Basic(S(3), S(1)))) == [Basic(S(3), S(2))]

    p1 = p**2
    p2 = p**3
    rl = rewriterule(p1, p2, variables=(p,))

    expr = x**2
    assert list(rl(expr)) == [x**3]

